import { useState, useEffect } from 'react';
import { organizationApi, personnelApi, seniorityApi } from '../../services/api';

const PlusIcon = () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>;
const EditIcon = () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>;
const TrashIcon = () => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>;
const ChevronIcon = ({ open }) => <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24" style={{ transform: open ? 'rotate(90deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }}><polyline points="9 18 15 12 9 6"/></svg>;

function UnitModal({ unit, units, onSave, onClose }) {
  const [name, setName] = useState(unit?.name || '');
  const [parentId, setParentId] = useState(unit?.parentId || '');
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  const roots = units.filter(u => !u.parentId);

  const handleSave = async () => {
    if (!name.trim()) return setError('Birim adı zorunludur.');
    setSaving(true);
    try {
      const data = { name: name.trim(), parentId: parentId || null };
      if (unit?.id) await organizationApi.update(unit.id, data);
      else await organizationApi.create(data);
      onSave();
    } catch (e) {
      setError(e.response?.data?.error || 'Bir hata oluştu.');
    } finally { setSaving(false); }
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 420 }}>
        <div className="modal-header">
          <div className="modal-title">{unit?.id ? 'Birimi Düzenle' : 'Yeni Birim'}</div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        {error && <div className="alert alert-error" style={{ margin: '0 0 16px' }}>{error}</div>}
        <div className="form-group">
          <label className="form-label">Birim Adı</label>
          <input className="form-input" value={name} onChange={e => setName(e.target.value)} placeholder="Birim adı" autoFocus />
        </div>
        <div className="form-group">
          <label className="form-label">Üst Birim (boş bırakılırsa üst birim olur)</label>
          <select className="form-input" value={parentId} onChange={e => setParentId(e.target.value)}>
            <option value="">— Üst Birim (kök) —</option>
            {roots.filter(r => r.id !== unit?.id).map(r => (
              <option key={r.id} value={r.id}>{r.name}</option>
            ))}
          </select>
        </div>
        <div className="form-actions">
          <button className="btn btn-ghost" onClick={onClose}>İptal</button>
          <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
            {saving ? 'Kaydediliyor...' : 'Kaydet'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function OrganizationPage() {
  const [units, setUnits] = useState([]);
  const [personnel, setPersonnel] = useState([]);
  const [seniorities, setSeniorities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [deleteError, setDeleteError] = useState('');
  const [openUnits, setOpenUnits] = useState({});

  const load = async () => {
    const [uRes, pRes, sRes] = await Promise.all([
      organizationApi.getAll(), personnelApi.getAll(), seniorityApi.getAll()
    ]);
    setUnits(uRes.data);
    setPersonnel(pRes.data);
    setSeniorities(sRes.data);
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const roots = units.filter(u => !u.parentId);
  const getChildren = (parentId) => units.filter(u => u.parentId === parentId);
  const getPersonnel = (unitId) => personnel.filter(p => p.unitId === unitId);
  const getSeniorityName = (id) => seniorities.find(s => s.id === id)?.name || '—';

  const toggleUnit = (id) => setOpenUnits(prev => ({ ...prev, [id]: !prev[id] }));

  const handleDelete = async (unit) => {
    try {
      await organizationApi.delete(unit.id);
      setDeleteConfirm(null);
      load();
    } catch (e) {
      setDeleteError(e.response?.data?.error || 'Silinemedi.');
    }
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Organizasyon Yönetimi</div>
          <div className="page-subtitle">Birimler ve personel yapısını yönetin</div>
        </div>
        <button className="btn btn-primary" onClick={() => { setEditing(null); setModalOpen(true); }}>
          <PlusIcon /> Yeni Birim
        </button>
      </div>

      {/* Özet kartlar */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 20 }}>
        {[
          { label: 'Üst Birim', value: roots.length, color: 'var(--accent)' },
          { label: 'Alt Birim', value: units.filter(u => u.parentId).length, color: '#7c3aed' },
          { label: 'Toplam Personel', value: personnel.length, color: 'var(--success)' },
          { label: 'Birimsiz Personel', value: personnel.filter(p => !p.unitId).length, color: 'var(--warning)' },
        ].map(c => (
          <div key={c.label} style={{ flex: 1, padding: '12px 16px', background: 'var(--bg-secondary)', borderRadius: 8, border: `1px solid ${c.color}33` }}>
            <div style={{ fontSize: 11, color: c.color, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: 4 }}>{c.label}</div>
            <div style={{ fontSize: 22, fontWeight: 700, color: c.color, fontFamily: 'DM Mono, monospace' }}>{c.value}</div>
          </div>
        ))}
      </div>

      {loading ? <div className="loading">Yükleniyor...</div> : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {roots.length === 0 && <div className="card"><div className="empty-state"><p>Henüz birim eklenmemiş.</p></div></div>}
          {roots.map(root => {
            const children = getChildren(root.id);
            const rootPersonnel = getPersonnel(root.id);
            const isOpen = openUnits[root.id] !== false; // default açık

            return (
              <div key={root.id} className="card" style={{ padding: 0, overflow: 'hidden' }}>
                {/* Üst birim başlığı */}
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 20px', background: 'var(--bg-hover)', borderBottom: isOpen ? '1px solid var(--border)' : 'none', cursor: 'pointer' }}
                  onClick={() => toggleUnit(root.id)}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <ChevronIcon open={isOpen} />
                    <span style={{ fontWeight: 700, fontSize: 15 }}>{root.name}</span>
                    <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 10, background: 'var(--accent)22', color: 'var(--accent)', fontWeight: 600 }}>
                      {children.length} alt birim · {children.reduce((s, c) => s + getPersonnel(c.id).length, 0) + rootPersonnel.length} kişi
                    </span>
                  </div>
                  <div style={{ display: 'flex', gap: 6 }} onClick={e => e.stopPropagation()}>
                    <button className="btn btn-ghost" style={{ padding: '4px 10px', fontSize: 12 }}
                      onClick={() => { setEditing({ parentId: root.id }); setModalOpen(true); }}>
                      <PlusIcon /> Alt Birim
                    </button>
                    <button className="btn-icon" onClick={() => { setEditing(root); setModalOpen(true); }}><EditIcon /></button>
                    <button className="btn-icon danger" onClick={() => { setDeleteError(''); setDeleteConfirm(root); }}><TrashIcon /></button>
                  </div>
                </div>

                {isOpen && (
                  <div style={{ padding: '12px 20px', display: 'flex', flexDirection: 'column', gap: 10 }}>
                    {children.length === 0 && rootPersonnel.length === 0 && (
                      <div style={{ color: 'var(--text-muted)', fontSize: 13, padding: '8px 0' }}>Alt birim veya personel yok.</div>
                    )}

                    {children.map(child => {
                      const childPersonnel = getPersonnel(child.id);
                      const isChildOpen = openUnits[child.id] !== false;
                      return (
                        <div key={child.id} style={{ border: '1px solid var(--border)', borderRadius: 8, overflow: 'hidden' }}>
                          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 16px', background: 'var(--bg-secondary)', cursor: 'pointer' }}
                            onClick={() => toggleUnit(child.id)}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                              <ChevronIcon open={isChildOpen} />
                              <span style={{ fontWeight: 600, fontSize: 13 }}>{child.name}</span>
                              <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 10, background: 'var(--bg-hover)', color: 'var(--text-muted)', fontWeight: 600 }}>
                                {childPersonnel.length} kişi
                              </span>
                            </div>
                            <div style={{ display: 'flex', gap: 6 }} onClick={e => e.stopPropagation()}>
                              <button className="btn-icon" onClick={() => { setEditing(child); setModalOpen(true); }}><EditIcon /></button>
                              <button className="btn-icon danger" onClick={() => { setDeleteError(''); setDeleteConfirm(child); }}><TrashIcon /></button>
                            </div>
                          </div>
                          {isChildOpen && childPersonnel.length > 0 && (
                            <div style={{ padding: '8px 16px 12px' }}>
                              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                                {childPersonnel.map(p => (
                                  <div key={p.id} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 12px', background: 'var(--bg-hover)', borderRadius: 8, border: '1px solid var(--border)' }}>
                                    <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'var(--accent)22', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700, color: 'var(--accent)' }}>
                                      {p.firstName[0]}{p.lastName[0]}
                                    </div>
                                    <div>
                                      <div style={{ fontSize: 13, fontWeight: 500 }}>{p.firstName} {p.lastName}</div>
                                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{getSeniorityName(p.seniorityId)}</div>
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}
                          {isChildOpen && childPersonnel.length === 0 && (
                            <div style={{ padding: '8px 16px', color: 'var(--text-muted)', fontSize: 12 }}>Personel yok.</div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {modalOpen && (
        <UnitModal unit={editing} units={units}
          onSave={() => { setModalOpen(false); load(); }}
          onClose={() => setModalOpen(false)} />
      )}

      {deleteConfirm && (
        <div className="modal-overlay" onClick={() => setDeleteConfirm(null)}>
          <div className="modal" style={{ maxWidth: 380 }} onClick={e => e.stopPropagation()}>
            <div className="modal-title" style={{ marginBottom: 8 }}>Birimi Sil</div>
            <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginBottom: 16 }}>
              <strong>{deleteConfirm.name}</strong> birimi silinecek. Bu işlem geri alınamaz.
            </p>
            {deleteError && <div className="alert alert-error" style={{ marginBottom: 12 }}>{deleteError}</div>}
            <div className="form-actions">
              <button className="btn btn-ghost" onClick={() => setDeleteConfirm(null)}>İptal</button>
              <button className="btn btn-danger" onClick={() => handleDelete(deleteConfirm)}>Sil</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
